// Extract and validate email
const input = $input.first().json;

const name = input['Full Name'] || '';
const email = input['Email'] || '';
const company = input['Company Name'] || '';
const phone = input['Phone'] || '';
const message = input['Message'] || '';

// Basic email validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValidEmail = emailRegex.test(email);

if (!isValidEmail) {
  throw new Error('Invalid email format');
}

// Extract domain from email
const domain = email.split('@')[1];

// Filter out free email providers
const freeProviders = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'aol.com'];
const isBusinessEmail = !freeProviders.includes(domain.toLowerCase());

return [{
  json: {
    name: name,
    email: email,
    company: company,
    phone: phone,
    message: message,
    domain: domain,
    is_business_email: isBusinessEmail,
    timestamp: new Date().toISOString()
  }
}];

// Extract website URL from Google search results
const response = $input.first().json;
const formData = $('Validate Email & Extract Domain').first().json;

let website = '';

if (response.items && response.items.length > 0) {
  website = response.items[0].link;
}

// Fallback: construct from domain
if (!website) {
  website = 'https://' + formData.domain;
}

return [{
  json: {
    ...formData,
    website: website
  }
}];

// Extract text content from HTML
const html = $input.first().binary?.data ? Buffer.from($input.first().binary.data, 'base64').toString() : '';
const formData = $('Extract Website URL').first().json;

// Simple HTML text extraction (remove tags)
let text = html.replace(/<script[^>]*>.*?<\/script>/gi, '')
               .replace(/<style[^>]*>.*?<\/style>/gi, '')
               .replace(/<[^>]+>/g, ' ')
               .replace(/\s+/g, ' ')
               .trim();

// Limit to first 3000 characters for AI analysis
text = text.substring(0, 3000);

// Detect tech stack from HTML
const usesMailchimp = html.includes('mailchimp') || html.includes('mc.us');
const usesActiveCampaign = html.includes('activecampaign') || html.includes('vgo.js');
const usesSalesforce = html.includes('salesforce.com');
const usesHubSpot = html.includes('hubspot') || html.includes('hs-scripts.com');

const detectedTech = [];
if (usesMailchimp) detectedTech.push('Mailchimp');
if (usesActiveCampaign) detectedTech.push('ActiveCampaign');
if (usesSalesforce) detectedTech.push('Salesforce');
if (usesHubSpot) detectedTech.push('HubSpot');

return [{
  json: {
    ...formData,
    website_content: text,
    detected_tech: detectedTech,
    tech_stack_match: detectedTech.length > 0
  }
}];

