// Parse AI analysis and funding search
const aiResponse = $('AI Website Analysis (Gemini)').first().json;
const fundingResponse = $input.first().json;
const formData = $('Parse HTML & Detect Tech Stack').first().json;

// Extract AI analysis from Gemini response
let aiData = {};
try {
  const aiText = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  // Remove markdown code blocks if present
  const cleanText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiData = JSON.parse(cleanText);
} catch (e) {
  console.log('Failed to parse AI response:', e);
  aiData = {
    estimated_employees: 0,
    industry: 'Unknown',
    estimated_revenue: 0,
    pain_points: [],
    buying_signals: [],
    is_saas: false,
    is_tech: false
  };
}

// Check for funding signals
const hasFundingNews = fundingResponse.items && fundingResponse.items.length > 0;
const fundingSnippets = hasFundingNews ? fundingResponse.items.slice(0, 3).map(item => item.snippet).join(' ') : '';
const recentFunding = fundingSnippets.toLowerCase().includes('raised') || fundingSnippets.toLowerCase().includes('funding');

if (recentFunding && !aiData.buying_signals.includes('Recent funding')) {
  aiData.buying_signals.push('Recent funding');
}

return [{
  json: {
    ...formData,
    ...aiData,
    recent_funding: recentFunding,
    funding_snippets: fundingSnippets
  }
}];

// Calculate lead score based on ICP fit
const data = $input.first().json;

let score = 0;
let scoreBreakdown = [];

// Tech stack match (30 points)
if (data.tech_stack_match && data.detected_tech.length > 0) {
  score += 30;
  scoreBreakdown.push(`Tech stack match (+30): ${data.detected_tech.join(', ')}`);
}

// Company size: 50-500 employees (25 points)
const employees = data.estimated_employees || 0;
if (employees >= 50 && employees <= 500) {
  score += 25;
  scoreBreakdown.push(`Company size fit (+25): ${employees} employees`);
} else if (employees > 0) {
  scoreBreakdown.push(`Company size mismatch (0): ${employees} employees`);
}

// Industry: SaaS/Tech (20 points)
if (data.is_saas || data.is_tech) {
  score += 20;
  scoreBreakdown.push(`Industry fit (+20): ${data.industry}`);
} else {
  scoreBreakdown.push(`Industry mismatch (0): ${data.industry}`);
}

// Revenue: $5M-$50M (15 points)
const revenue = data.estimated_revenue || 0;
if (revenue >= 5000000 && revenue <= 50000000) {
  score += 15;
  scoreBreakdown.push(`Revenue fit (+15): $${(revenue/1000000).toFixed(1)}M`);
} else if (revenue > 0) {
  scoreBreakdown.push(`Revenue mismatch (0): $${(revenue/1000000).toFixed(1)}M`);
}

// Buying signals (10 points)
if (data.buying_signals.length > 0 || data.recent_funding) {
  score += 10;
  scoreBreakdown.push(`Buying signals (+10): ${data.buying_signals.join(', ')}`);
}

// Determine status
let status = '';
let action = '';

if (score >= 70) {
  status = 'Hot Lead';
  action = 'generate_email';
} else if (score >= 40) {
  status = 'Warm Lead';
  action = 'nurture';
} else {
  status = 'Cold Lead';
  action = 'archive';
}

// Generate archive reason for cold leads
let archiveReason = '';
if (score < 40) {
  const reasons = [];
  if (!data.tech_stack_match) reasons.push('No target tech stack detected');
  if (employees > 0 && (employees < 50 || employees > 500)) reasons.push(`Company size (${employees}) outside range`);
  if (!data.is_saas && !data.is_tech) reasons.push(`Industry (${data.industry}) not SaaS/Tech`);
  if (revenue > 0 && (revenue < 5000000 || revenue > 50000000)) reasons.push(`Revenue outside target range`);
  archiveReason = reasons.join('; ');
}

return [{
  json: {
    ...data,
    lead_score: score,
    score_breakdown: scoreBreakdown,
    status: status,
    action: action,
    archive_reason: archiveReason
  }
}];

